// The damaged item is the policy item whose type the damage names. Today every
// damage references an insured type, so the lookup always succeeds; the upcoming
// "claim references item not in policy" test will give this its own failure path.
const insuredItemFor = (damage: Damage, policy: Policy): Item =>
  policy.items.find((item) => item.type === damage.itemType)!;

const damagePayout = (damage: Damage, policy: Policy): number =>
  reimbursement(insuredItemFor(damage, policy), damage.amount) - DEDUCTIBLE;
